from flask import Flask, send_file, request
import os

app = Flask(__name__)

# Assuming invoices are stored in a directory named 'invoices'
INVOICES_DIR = '/path/to/invoices'

@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    invoice_path = os.path.join(INVOICES_DIR, f'{invoice_id}.pdf')
    
    if not os.path.exists(invoice_path):
        return 'Invoice not found', 404
    
    return send_file(invoice_path, as_attachment=True, attachment_filename=f'invoice_{invoice_id}.pdf')

if __name__ == '__main__':
    app.run(debug=True)